import React, { useState, useEffect, useCallback, useRef } from 'react';
import axios from 'axios';
import Timer from './Timer';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout }) => {
  const [questions, setQuestions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [submitting, setSubmitting] = useState(false);

  // Simple tab switch detection
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden) {
        setTabSwitchCount(prev => prev + 1);
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, []);

  // Fetch questions
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        setQuestions(response.data.questions);
      } catch (err) {
        setError('Failed to load questions');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchQuestions();
  }, [quizId]);

  // Handle answer selection
  const handleAnswerSelect = (questionId, option) => {
    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    // Auto move to next question after 300ms
    setTimeout(() => {
      if (currentIndex < questions.length - 1) {
        setCurrentIndex(prev => prev + 1);
      }
    }, 300);
  };

  // Handle quiz submission
  const handleSubmit = async () => {
    if (submitting) return;

    // Check if all questions are answered
    if (Object.keys(answers).length !== questions.length) {
      alert(`Please answer all questions. You have answered ${Object.keys(answers).length} out of ${questions.length}`);
      return;
    }

    setSubmitting(true);

    try {
      const answersList = Object.entries(answers).map(([qId, selected]) => ({
        question_id: parseInt(qId),
        selected_option: selected
      }));

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCount
      });

      onSubmit({
        score: response.data.score,
        totalQuestions: response.data.total_questions,
        timeTaken: response.data.time_taken_microseconds
      });

    } catch (err) {
      console.error('Submission error:', err);
      if (err.response) {
        alert(`Error: ${err.response.data.detail || 'Submission failed'}`);
      } else if (err.request) {
        alert('Cannot connect to server. Please check if backend is running.');
      } else {
        alert('Failed to submit quiz. Please try again.');
      }
      setSubmitting(false);
    }
  };

  // Handle time up
  const handleTimeUp = () => {
    if (Object.keys(answers).length > 0) {
      handleSubmit();
    }
    onTimeout();
  };

  // Loading state
  if (loading) {
    return (
      <div style={{ maxWidth: '600px', margin: '40px auto', padding: '20px' }}>
        <div style={{ textAlign: 'center' }}>Loading questions...</div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div style={{ maxWidth: '600px', margin: '40px auto', padding: '20px' }}>
        <div style={{ color: 'red', textAlign: 'center' }}>{error}</div>
        <button 
          onClick={() => window.location.reload()}
          style={{ marginTop: '20px', padding: '10px 20px' }}
        >
          Retry
        </button>
      </div>
    );
  }

  const currentQuestion = questions[currentIndex];
  const progress = `${Object.keys(answers).length}/${questions.length}`;

  return (
    <div style={{ maxWidth: '600px', margin: '0 auto', padding: '20px' }}>
      {/* Header */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        marginBottom: '30px',
        padding: '15px 0',
        borderBottom: '1px solid #eee'
      }}>
        <span style={{ fontWeight: '500' }}>
          Question {currentIndex + 1}/{questions.length}
        </span>
        <Timer 
          initialSeconds={1800}
          onTimeUp={handleTimeUp}
          isActive={!submitting}
        />
      </div>

      {/* Tab switch warning */}
      {tabSwitchCount > 0 && (
        <div style={{ 
          backgroundColor: '#fff3cd', 
          color: '#856404',
          padding: '10px',
          marginBottom: '20px',
          fontSize: '14px'
        }}>
          ⚠️ Tab switching detected ({tabSwitchCount} time{tabSwitchCount !== 1 ? 's' : ''})
        </div>
      )}

      {/* Question */}
      <div style={{ marginBottom: '30px' }}>
        <h3 style={{ 
          fontSize: '20px', 
          fontWeight: 'normal',
          marginBottom: '20px'
        }}>
          {currentQuestion?.question}
        </h3>

        {/* Options as radio buttons */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          {currentQuestion?.options.map((option, idx) => {
            const optionId = `q${currentQuestion.id}_opt${idx}`;
            const isSelected = answers[currentQuestion.id] === option;

            return (
              <div 
                key={idx}
                onClick={() => !submitting && handleAnswerSelect(currentQuestion.id, option)}
                style={{ 
                  display: 'flex', 
                  alignItems: 'center',
                  cursor: submitting ? 'default' : 'pointer',
                  padding: '5px 0'
                }}
              >
                <input
                  type="radio"
                  id={optionId}
                  name={`question_${currentQuestion.id}`}
                  value={option}
                  checked={isSelected}
                  onChange={() => {}} // Handled by div click
                  disabled={submitting}
                  style={{ 
                    width: '18px', 
                    height: '18px',
                    marginRight: '12px',
                    cursor: submitting ? 'default' : 'pointer'
                  }}
                />
                <label 
                  htmlFor={optionId}
                  style={{ 
                    cursor: submitting ? 'default' : 'pointer',
                    fontSize: '16px',
                    color: isSelected ? '#2563eb' : '#333'
                  }}
                >
                  {option}
                </label>
              </div>
            );
          })}
        </div>
      </div>

      {/* Progress and submit */}
      <div style={{ 
        borderTop: '1px solid #eee',
        paddingTop: '20px',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <span style={{ color: '#666' }}>
          Answered: {progress}
        </span>

        {Object.keys(answers).length === questions.length && !submitting && (
          <button
            onClick={handleSubmit}
            style={{
              backgroundColor: '#2563eb',
              color: 'white',
              border: 'none',
              padding: '10px 30px',
              borderRadius: '6px',
              fontSize: '16px',
              cursor: 'pointer'
            }}
          >
            Submit Quiz
          </button>
        )}

        {submitting && (
          <span style={{ color: '#666' }}>Submitting...</span>
        )}
      </div>
    </div>
  );
};

export default QuizPage;
